def decode_rule_key(key: int, bucket_delta: int = 0) -> dict[str, int]:
    return {
        "x": ((int(key) & 0x00FF) << 4) | ((int(key) >> 8) & 0x0F),
        "y": int(bucket_delta) * 16 + ((int(key) >> 12) & 0x0F),
        "row_low": (int(key) >> 12) & 0x0F,
        "subbyte": (int(key) >> 8) & 0x0F,
        "byte_pair_offset": (int(key) & 0x00FF) * 2,
    }


def rule_masks_via_1f6ee(data: bytes, subbyte: int, width: int) -> dict[str, int]:
    phase = int(subbyte) & 0x0F
    first_word_bits = 16 - phase
    left_mask = u16(data, 0x3089E + phase * 2)
    right_mask = 0
    if int(width) >= 16:
        right_index = (int(width) - first_word_bits) & 0x0F
        right_mask = u16(data, 0x308BE + right_index * 2)
    else:
        right_index = phase + int(width) - 16
        if right_index >= 0:
            right_mask = u16(data, 0x308BE + right_index * 2)
        else:
            left_mask &= u16(data, 0x308BE + (right_index + 16) * 2)
    interior_words = (int(width) - first_word_bits) >> 4
    if interior_words < 0:
        interior_words = 0
    return {
        "left_mask": left_mask,
        "right_mask": right_mask,
        "interior_words": interior_words,
    }


def prepare_rule_object_for_band(obj: bytes | bytearray, band_word: int = 0) -> dict[str, object]:
    node = bytearray(obj)
    key = u16(node, 6)
    remaining = int.from_bytes(node[0x0C:0x0E], "big", signed=True)
    bucket_delta = (node[4] - int(band_word)) & 0xFF
    bridged_current_band = bool(node[5] & 0x10)
    if remaining <= 0:
        rows_to_draw = 0
        available_rows = 0
    elif bridged_current_band:
        node[5] &= ~0x10
        available_rows = 0x50 - ((key >> 12) & 0x0F) - 0x10 * bucket_delta
        rows_to_draw = min(remaining, max(available_rows, 0))
        node[0x0C:0x0E] = ((remaining - available_rows) & 0xFFFF).to_bytes(2, "big")
    else:
        key &= 0x0FFF
        bucket_delta = 0
        available_rows = 0x50 - ((key >> 12) & 0x0F)
        rows_to_draw = min(remaining, max(available_rows, 0))
        node[0x0C:0x0E] = ((remaining - available_rows) & 0xFFFF).to_bytes(2, "big")
    return {
        "node": node,
        "key": key,
        "bucket_delta": bucket_delta,
        "remaining_before": remaining,
        "available_rows": available_rows,
        "rows_to_draw": rows_to_draw,
    }


def render_solid_rule_object_via_1f596(data: bytes, obj: bytes | bytearray, band_word: int = 0, dest_stride: int = 0x20, band_rows: int = 80) -> dict[str, object]:
    prepared = prepare_rule_object_for_band(obj, band_word)
    node = prepared["node"]
    assert isinstance(node, bytearray)
    selector = node[5] & 0x0F
    if selector != 7:
        raise AssertionError("0x1f596 fixture only renders solid selector 7")
    key = int(prepared["key"])
    width = u16(node, 8)
    bucket_delta = int(prepared["bucket_delta"])
    rows_to_draw = int(prepared["rows_to_draw"])
    decoded = decode_rule_key(key, bucket_delta)
    dest = bytearray(band_rows * dest_stride)
    if rows_to_draw:
        span = (width + 15) // 16 * 2
        source = bytearray(rows_to_draw * span)
        full_words = width >> 4
        partial_bits = width & 0x0F
        partial_mask = u16(data, 0x308BE + partial_bits * 2) if partial_bits else 0
        for row in range(rows_to_draw):
            pos = row * span
            for _ in range(full_words):
                source[pos:pos + 2] = b"\xff\xff"
                pos += 2
            if partial_bits:
                source[pos:pos + 2] = partial_mask.to_bytes(2, "big")
        write_bitmap_bits(dest, dest_stride, bytes(source), rows_to_draw, span, int(decoded["x"]), int(decoded["y"]))
    else:
        full_words = width >> 4
        partial_bits = width & 0x0F
        partial_mask = u16(data, 0x308BE + partial_bits * 2) if partial_bits else 0

    max_bottom = min(band_rows, int(decoded["y"]) + rows_to_draw)
    max_width = int(decoded["x"]) + width
    return {
        "selector": selector,
        "helper": 0x1F596,
        "key": key,
        "bucket_delta": bucket_delta,
        "decoded": decoded,
        "width": width,
        "remaining_before": int(prepared["remaining_before"]),
        "available_rows": int(prepared["available_rows"]),
        "rows_drawn": rows_to_draw,
        "full_words": full_words,
        "partial_bits": partial_bits,
        "partial_mask": partial_mask,
        "mutated_object": bytes(node),
        "rows": bitmap_bytes_to_rows(dest, max_bottom, max_width, dest_stride),
    }


def render_pattern_rule_object_via_1f4e0(data: bytes, obj: bytes | bytearray, band_word: int = 0, dest_stride: int = 0x20, band_rows: int = 80) -> dict[str, object]:
    prepared = prepare_rule_object_for_band(obj, band_word)
    node = prepared["node"]
    assert isinstance(node, bytearray)
    selector = node[5] & 0x0F
    if selector == 7:
        raise AssertionError("0x1f4e0 fixture does not render solid selector 7")
    key = int(prepared["key"])
    width = u16(node, 8)
    bucket_delta = int(prepared["bucket_delta"])
    rows_to_draw = int(prepared["rows_to_draw"])
    decoded = decode_rule_key(key, bucket_delta)
    masks = rule_masks_via_1f6ee(data, int(decoded["subbyte"]), width)
    pattern_base = u32(data, 0x2FEFE + selector * 4)
    pattern_start = pattern_base + int(decoded["row_low"]) * 2
    pattern_words = [u16(data, pattern_start + row * 2) for row in range(rows_to_draw)]
    span = (width + 15) // 16 * 2
    dest = bytearray(band_rows * dest_stride)
    source = bytearray(rows_to_draw * span)
    for row, word in enumerate(pattern_words):
        for bit in range(width):
            if word & (0x8000 >> (bit & 0x0F)):
                source[row * span + bit // 8] |= 0x80 >> (bit & 7)
    if rows_to_draw:
        write_bitmap_bits(dest, dest_stride, bytes(source), rows_to_draw, span, int(decoded["x"]), int(decoded["y"]))
    max_bottom = min(band_rows, int(decoded["y"]) + rows_to_draw)
    max_width = int(decoded["x"]) + width
    return {
        "selector": selector,
        "helper": 0x1F4E0,
        "key": key,
        "bucket_delta": bucket_delta,
        "decoded": decoded,
        "width": width,
        "remaining_before": int(prepared["remaining_before"]),
        "available_rows": int(prepared["available_rows"]),
        "rows_drawn": rows_to_draw,
        "pattern_base": pattern_base,
        "pattern_start": pattern_start,
        "pattern_words": pattern_words,
        "left_mask": masks["left_mask"],
        "interior_words": masks["interior_words"],
        "right_mask": masks["right_mask"],
        "mutated_object": bytes(node),
        "rows": bitmap_bytes_to_rows(dest, max_bottom, max_width, dest_stride),
    }


def render_rule_list_via_1f446(data: bytes, render_record: dict[str, object], band_word: int = 0, dest_stride: int = 0x20, band_rows: int = 80) -> dict[str, object]:
    if band_word % 5:
        return {"band_word": band_word, "rendered": [], "rows": []}
    rendered: list[dict[str, object]] = []
    dest = bytearray(band_rows * dest_stride)
    max_bottom = 0
    max_width = 0
    for raw in render_record.get("rule_list", []):
        obj = bytes(raw)
        if obj[4] > band_word + 4:
            break
        if int.from_bytes(obj[0x0C:0x0E], "big", signed=True) <= 0:
            continue
        selector = obj[5] & 0x0F
        if selector == 7:
            item = render_solid_rule_object_via_1f596(data, obj, band_word=band_word, dest_stride=dest_stride, band_rows=band_rows)
        else:
            item = render_pattern_rule_object_via_1f4e0(data, obj, band_word=band_word, dest_stride=dest_stride, band_rows=band_rows)
        rendered.append(item)
        rows = item["rows"]
        assert isinstance(rows, list)
        for row_index, row in enumerate(rows):
            for x, pixel in enumerate(row):
                if pixel == "#":
                    dest[row_index * dest_stride + x // 8] |= 0x80 >> (x & 7)
        max_bottom = max(max_bottom, len(rows))
        max_width = max(max_width, max((len(row) for row in rows), default=0))
    return {
        "band_word": band_word,
        "rendered": rendered,
        "rows": bitmap_bytes_to_rows(dest, max_bottom, max_width, dest_stride),
    }


def render_rule_page_bands_via_1f446(data: bytes, render_record: dict[str, object], band_words: tuple[int, ...], page_rows: int, page_width: int, dest_stride: int = 0x20, band_rows: int = 80) -> dict[str, object]:
    active = [bytes(raw) for raw in render_record.get("rule_list", [])]
    page = [["." for _ in range(page_width)] for _ in range(page_rows)]
    band_reports: list[dict[str, object]] = []
    for band_word in band_words:
        rendered = render_rule_list_via_1f446(data, {"rule_list": active}, band_word=band_word, dest_stride=dest_stride, band_rows=band_rows)
        band_top = (band_word // 5) * band_rows
        rows = rendered["rows"]
        assert isinstance(rows, list)
        for row_index, row in enumerate(rows):
            page_y = band_top + row_index
            if page_y >= page_rows:
                break
            for x, pixel in enumerate(row[:page_width]):
                if pixel == "#":
                    page[page_y][x] = "#"

        rendered_items = list(rendered["rendered"])
        rendered_iter = iter(rendered_items)
        carried: list[bytes] = []
        for obj in active:
            if obj[4] > band_word + 4:
                carried.append(obj)
                continue
            if int.from_bytes(obj[0x0C:0x0E], "big", signed=True) <= 0:
                continue
            item = next(rendered_iter)
            mutated = item["mutated_object"]
            assert isinstance(mutated, bytes)
            if int.from_bytes(mutated[0x0C:0x0E], "big", signed=True) > 0:
                carried.append(mutated)
        band_reports.append({
            "band_word": band_word,
            "rendered": rendered_items,
            "rows": rows,
            "carried": carried,
        })
        active = carried

    return {
        "bands": band_reports,
        "remaining": active,
        "rows": ["".join(row) for row in page],
    }


def render_fixed_width_object_via_1f7b0(data: bytes, obj: bytes | bytearray, band_word: int = 0, dest_stride: int = 0x20, band_rows: int = 80) -> dict[str, object]:
    node = bytearray(obj)
    selector = node[5] & 0x0F
    pattern_table_entry = 0x308DE + selector * 4
    pattern_long = u32(data, pattern_table_entry)
    pattern_word = pattern_long & 0xFFFF
    key = u16(node, 6)
    remaining = int.from_bytes(node[0x0A:0x0C], "big", signed=True)
    bucket_delta = (node[4] - int(band_word)) & 0xFF
    bridged_current_band = bool(node[5] & 0x10)
    if remaining <= 0:
        rows_to_draw = 0
        available_rows = 0
    elif bridged_current_band:
        node[5] &= ~0x10
        available_rows = 0x50 - ((key >> 12) & 0x0F) - 0x10 * bucket_delta
        rows_to_draw = min(remaining, max(available_rows, 0))
        node[0x0A:0x0C] = ((remaining - available_rows) & 0xFFFF).to_bytes(2, "big")
    else:
        key &= 0x0FFF
        bucket_delta = 0
        available_rows = 0x50 - ((key >> 12) & 0x0F)
        rows_to_draw = min(remaining, max(available_rows, 0))
        node[0x0A:0x0C] = ((remaining - available_rows) & 0xFFFF).to_bytes(2, "big")

    decoded = decode_rule_key(key, bucket_delta)
    dest = bytearray(band_rows * dest_stride)
    if rows_to_draw:
        source = pattern_word.to_bytes(2, "big") * rows_to_draw
        write_bitmap_bits(dest, dest_stride, source, rows_to_draw, 2, int(decoded["x"]), int(decoded["y"]))
    max_bottom = min(band_rows, int(decoded["y"]) + rows_to_draw)
    max_width = int(decoded["x"]) + 16
    return {
        "selector": selector,
        "helper": 0x1F7B0,
        "pattern_table_entry": pattern_table_entry,
        "pattern_long": pattern_long,
        "pattern_word": pattern_word,
        "key": key,
        "bucket_delta": bucket_delta,
        "decoded": decoded,
        "remaining_before": remaining,
        "available_rows": available_rows,
        "rows_drawn": rows_to_draw,
        "mutated_object": bytes(node),
        "rows": bitmap_bytes_to_rows(dest, max_bottom, max_width, dest_stride),
    }


def render_fixed_width_list_via_1f756(data: bytes, render_record: dict[str, object], band_word: int = 0, dest_stride: int = 0x20, band_rows: int = 80) -> dict[str, object]:
    if band_word % 5:
        return {"band_word": band_word, "rendered": [], "rows": []}
    rendered: list[dict[str, object]] = []
    layers: list[list[str]] = []
    max_width = 0
    max_rows = 0
    for raw in render_record.get("fixed_list", []):
        obj = bytes(raw)
        if obj[4] > band_word + 4:
            break
        if int.from_bytes(obj[0x0A:0x0C], "big", signed=True) <= 0:
            continue
        item = render_fixed_width_object_via_1f7b0(data, obj, band_word=band_word, dest_stride=dest_stride, band_rows=band_rows)
        rendered.append(item)
        rows = item["rows"]
        assert isinstance(rows, list)
        layers.append(rows)
        max_rows = max(max_rows, len(rows))
        max_width = max(max_width, max((len(row) for row in rows), default=0))
    return {
        "band_word": band_word,
        "rendered": rendered,
        "rows": compose_set_pixel_rows(layers, max_width, max_rows) if layers else [],
    }


def render_band_entry_via_1ef6a(data: bytes, resources: bytes, render_record: dict[str, object], dest_stride: int = 0x20, band_rows: int = 80) -> dict[str, object]:
    """Model the 0x1ef6a per-band call order over a synthetic render record."""
    fields = render_record.get("render_record_fields", {})
    if not isinstance(fields, dict):
        fields = {}
    band_word = int(fields.get("word_10", render_record.get("word_10", 0))) & 0xFFFF
    context_slots = render_record.get("context_slots", fields.get("context_slots_24", ()))
    if not isinstance(context_slots, tuple):
        context_slots = tuple(context_slots) if isinstance(context_slots, list) else ()

    setup = compute_render_band_state_via_1ef86(render_record)
    bucket_band_rows = int(setup["band_rows_scaled_783a20"])
    dispatch = classify_bucket_chain_via_1efc2(data, render_record)
    bucket_heads = render_record.get("bucket_array_18", fields.get("bucket_array_18", {}))
    if not isinstance(bucket_heads, dict):
        raise AssertionError("0x1ef6a fixture needs render-record bucket array at +0x18")
    chain = bucket_heads.get(band_word, [])
    if not isinstance(chain, list):
        raise AssertionError("0x1ef6a fixture bucket entry must be a list")

    bucket_rendered: list[dict[str, object]] = []
    layers: list[list[str]] = []
    max_width = 0
    max_rows = 0
    for entry, raw in zip(dispatch["entries"], chain):
        obj = bytes(raw)
        branch = entry["branch"]
        if branch == "compact":
            item = render_compact_text_bucket_object(data, resources, context_slots, obj, band_rows=bucket_band_rows)
        elif branch == "segment-list":
            item = render_segment_list_object_via_1f812(data, obj, dest_stride=dest_stride, band_rows=bucket_band_rows)
        elif branch == "encoded-span":
            item = render_encoded_raster_object_via_1f88e(data, obj, dest_stride=dest_stride, band_rows=bucket_band_rows)
        else:
            raise AssertionError(f"unsupported 0x1efc2 branch {branch!r}")
        bucket_rendered.append({"branch": branch, "object": obj, "rendered": item})
        rows = item["rows"]
        assert isinstance(rows, list)
        layers.append(rows)
        max_rows = max(max_rows, len(rows))
        max_width = max(max_width, max((len(row) for row in rows), default=0))

    rule_record = {"rule_list": render_record.get("rule_list", fields.get("rule_list_1c", []))}
    rules = render_rule_list_via_1f446(data, rule_record, band_word=band_word, dest_stride=dest_stride, band_rows=band_rows)
    rule_rows = rules["rows"]
    assert isinstance(rule_rows, list)
    if rule_rows:
        layers.append(rule_rows)
        max_rows = max(max_rows, len(rule_rows))
        max_width = max(max_width, max((len(row) for row in rule_rows), default=0))

    fixed_record = {"fixed_list": render_record.get("fixed_list", fields.get("fixed_list_20", []))}
    fixed = render_fixed_width_list_via_1f756(data, fixed_record, band_word=band_word, dest_stride=dest_stride, band_rows=band_rows)
    fixed_rows = fixed["rows"]
    assert isinstance(fixed_rows, list)
    if fixed_rows:
        layers.append(fixed_rows)
        max_rows = max(max_rows, len(fixed_rows))
        max_width = max(max_width, max((len(row) for row in fixed_rows), default=0))

    return {
        "call_order": [0x1EF86, 0x1EFC2, 0x1F446, 0x1F756],
        "band_word": band_word,
        "setup": setup,
        "dispatch": dispatch,
        "bucket_rendered": bucket_rendered,
        "rules": rules,
        "fixed": fixed,
        "rows": compose_set_pixel_rows(layers, max_width, max_rows) if layers else [],
    }


def carry_rule_or_fixed_list_after_band(
    active: list[bytes],
    rendered_items: list[dict[str, object]],
    band_word: int,
    remaining_slice: slice,
) -> list[bytes]:
    rendered_iter = iter(rendered_items)
    carried: list[bytes] = []
    for obj in active:
        if obj[4] > int(band_word) + 4:
            carried.append(obj)
            continue
        if int.from_bytes(obj[remaining_slice], "big", signed=True) <= 0:
            continue
        item = next(rendered_iter)
        mutated = item["mutated_object"]
        assert isinstance(mutated, bytes)
        if int.from_bytes(mutated[remaining_slice], "big", signed=True) > 0:
            carried.append(mutated)
    return carried


def render_page_bands_via_1ef6a(
    data: bytes,
    resources: bytes,
    render_record: dict[str, object],
    band_words: tuple[int, ...],
    page_rows: int,
    page_width: int,
    dest_stride: int = 0x20,
    band_rows: int = 80,
) -> dict[str, object]:
    fields = render_record.get("render_record_fields", {})
    if not isinstance(fields, dict):
        fields = {}
    active_rule_list = [
        bytes(raw)
        for raw in render_record.get("rule_list", fields.get("rule_list_1c", []))
    ]
    active_fixed_list = [
        bytes(raw)
        for raw in render_record.get("fixed_list", fields.get("fixed_list_20", []))
    ]
    page = [["." for _ in range(page_width)] for _ in range(page_rows)]
    band_reports: list[dict[str, object]] = []
    for band_word in band_words:
        band_record = dict(render_record)
        band_fields = dict(fields)
        band_fields["word_10"] = int(band_word) & 0xFFFF
        band_fields["rule_list_1c"] = active_rule_list
        band_fields["fixed_list_20"] = active_fixed_list
        band_record["render_record_fields"] = band_fields
        band_record["rule_list"] = active_rule_list
        band_record["fixed_list"] = active_fixed_list

        entry = render_band_entry_via_1ef6a(
            data,
            resources,
            band_record,
            dest_stride=dest_stride,
            band_rows=band_rows,
        )
        band_top = (int(band_word) // 5) * band_rows
        rows = entry["rows"]
        assert isinstance(rows, list)
        for row_index, row in enumerate(rows):
            page_y = band_top + row_index
            if page_y >= page_rows:
                break
            for x, pixel in enumerate(row[:page_width]):
                if pixel == "#":
                    page[page_y][x] = "#"

        rule_rendered = list(entry["rules"]["rendered"])
        fixed_rendered = list(entry["fixed"]["rendered"])
        active_rule_list = carry_rule_or_fixed_list_after_band(
            active_rule_list,
            rule_rendered,
            int(band_word),
            slice(0x0C, 0x0E),
        )
        active_fixed_list = carry_rule_or_fixed_list_after_band(
            active_fixed_list,
            fixed_rendered,
            int(band_word),
            slice(0x0A, 0x0C),
        )
        band_reports.append({
            "band_word": int(band_word),
            "entry": entry,
            "rows": rows,
            "carried_rule_list": active_rule_list,
            "carried_fixed_list": active_fixed_list,
        })

    return {
        "bands": band_reports,
        "remaining_rule_list": active_rule_list,
        "remaining_fixed_list": active_fixed_list,
        "rows": ["".join(row) for row in page],
    }


def render_published_page_record_via_1ed84_1ef6a(
    data: bytes,
    resources: bytes,
    published_page_record: dict[str, object],
    *,
    base_pointer: int = 0x00100000,
    width_word: int = 0x0020,
    band_divisor: int = 0x0005,
) -> dict[str, object]:
    """Carry a modeled 0xff1e published pool record through 0x1ed84 and 0x1ef6a."""
    render_record = copy_active_page_record_to_render_record_via_1ed84(published_page_record)
    fields = render_record["render_record_fields"]
    if not isinstance(fields, dict):
        raise AssertionError("published page-record render entry needs render-record fields")
    fields = dict(fields)
    fields.update({
        "long_00": int(base_pointer) & 0xFFFFFFFF,
        "word_04": int(width_word) & 0xFFFF,
        "word_06": int(band_divisor) & 0xFFFF,
        "word_08": int(fields.get("word_08", 0)) & 0xFFFF,
    })
    bucket_word = int(fields.get("word_10", 0)) & 0xFFFF
    source_bucket_array = published_page_record.get(
        "bucket_array",
        fields.get("bucket_array_18", fields.get("bucket_array_1c", {})),
    )
    if isinstance(source_bucket_array, dict) and source_bucket_array:
        fields["bucket_array_18"] = {
            int(index) & 0xFFFF: [bytes(obj) for obj in chain]
            for index, chain in source_bucket_array.items()
        }
    else:
        bucket_root = fields.get("bucket_root_18", render_record.get("bucket_root"))
        if isinstance(bucket_root, bytes):
            fields["bucket_array_18"] = {bucket_word: [bucket_root]}
        else:
            fields["bucket_array_18"] = {bucket_word: []}
    render_record["render_record_fields"] = fields
    entry = render_band_entry_via_1ef6a(data, resources, render_record)
    return {
        "active_copy": render_record["active_record_copy_fields"],
        "render_record_fields": fields,
        "entry": entry,
    }


def render_bucket_page_record_via_1ed84_1ef6a(
    data: bytes,
    resources: bytes,
    page_record: dict[str, object],
    *,
    bucket_word: int = 0,
    base_pointer: int = 0x00100000,
    width_word: int = 0x0020,
    band_divisor: int = 0x0005,
) -> dict[str, object]:
    """Carry a page-record bucket array through 0x1ed84 and 0x1ef6a."""
    bucket_array = page_record.get("bucket_array", {})
    if not isinstance(bucket_array, dict):
        raise AssertionError("bucket page-record render entry needs a bucket array")
    chain = [bytes(obj) for obj in bucket_array.get(bucket_word, [])]
    bridge_source = dict(page_record)
    if chain and not isinstance(bridge_source.get("bucket_root"), bytes):
        bridge_source["bucket_root"] = chain[0]

    render_record = copy_active_page_record_to_render_record_via_1ed84(bridge_source)
    fields = render_record["render_record_fields"]
    if not isinstance(fields, dict):
        raise AssertionError("bucket page-record render entry needs render-record fields")
    fields = dict(fields)
    fields.update({
        "long_00": int(base_pointer) & 0xFFFFFFFF,
        "word_04": int(width_word) & 0xFFFF,
        "word_06": int(band_divisor) & 0xFFFF,
        "word_08": int(fields.get("word_08", 0)) & 0xFFFF,
        "word_10": int(bucket_word) & 0xFFFF,
        "bucket_array_18": {int(bucket_word) & 0xFFFF: chain},
    })
    render_record["render_record_fields"] = fields
    entry = render_band_entry_via_1ef6a(data, resources, render_record)
    return {
        "active_copy": render_record["active_record_copy_fields"],
        "chain": chain,
        "render_record_fields": fields,
        "entry": entry,
    }


def rectangle_command_state(**overrides: object) -> dict[str, object]:
    state: dict[str, object] = {
        "width": pack12(0),
        "height": pack12(0),
        "area_fill_id": 0,
        "fill_selector": 7,
        "cursor_x": pack12(10),
        "cursor_y": pack12(20),
        "page_width": 100,
        "page_height": 80,
        "orientation": 0,
        "page_record": {},
        "page_roots": 0,
        "page_finalizes": 0,
        "events": [],
    }
    state.update(overrides)
    return state


def apply_rectangle_area_fill_id_via_10dce(state: dict[str, object], parameter: int | None) -> dict[str, object]:
    updated = dict(state)
    events = list(updated.get("events", []))
    value = 0 if parameter is None or int(parameter) == 0 else abs(int(parameter))
    updated["area_fill_id"] = value & 0xFFFF
    events.append({"kind": "rectangle-area-fill-id", "area_fill_id": int(updated["area_fill_id"])})
    updated["events"] = events
    return updated


def rectangle_decipoints_to_packed12(integer: int, fraction: int = 0) -> int:
    whole = int(integer)
    frac = int(fraction)
    if whole < 0 or (whole == 0 and frac == 0):
        return pack12(0)
    subunits = whole * 5
    fractional_product = frac * 5
    subunits += trunc_div(fractional_product, 10000)
    if fractional_product % 10000:
        subunits += 1
    subunits += 11
    return subunits_to_packed12(subunits)


def apply_rectangle_size_dots(state: dict[str, object], axis: str, parameter: int | None) -> dict[str, object]:
    updated = dict(state)
    events = list(updated.get("events", []))
    value = 0 if parameter is None or int(parameter) <= 0 else int(parameter)
    field = "width" if axis == "width" else "height"
    updated[field] = pack12(value)
    events.append({"kind": f"rectangle-{field}-dots", field: int(updated[field])})
    updated["events"] = events
    return updated


def apply_rectangle_size_decipoints(state: dict[str, object], axis: str, integer: int | None, fraction: int = 0) -> dict[str, object]:
    updated = dict(state)
    events = list(updated.get("events", []))
    value = pack12(0) if integer is None else rectangle_decipoints_to_packed12(int(integer), int(fraction))
    field = "width" if axis == "width" else "height"
    updated[field] = value
    events.append({"kind": f"rectangle-{field}-decipoints", field: int(updated[field])})
    updated["events"] = events
    return updated


def fill_selector_for_cP(parameter: int | None, area_fill_id: int, orientation: int) -> int | None:
    if parameter is None or int(parameter) == 0:
        return 7
    mode = abs(int(parameter))
    if mode == 2:
        if int(area_fill_id) < 1:
            return None
        thresholds = ((2, 0), (10, 1), (20, 2), (35, 3), (55, 4), (80, 5), (99, 6), (100, 7))
        for limit, selector in thresholds:
            if int(area_fill_id) <= limit:
                return selector
        return None
    if mode == 3:
        if not 1 <= int(area_fill_id) <= 6:
            return None
        selector = int(area_fill_id) + 7
        if int(orientation) == 1:
            return {1: 9, 2: 8, 3: 11, 4: 10}.get(int(area_fill_id), selector)
        return selector
    return None


def apply_fill_rectangle_via_10898(state: dict[str, object], parameter: int | None) -> dict[str, object]:
    updated = dict(state)
    events = list(updated.get("events", []))
    selector = fill_selector_for_cP(parameter, int(updated.get("area_fill_id", 0)), int(updated.get("orientation", 0)))
    if selector is None:
        events.append({"kind": "rectangle-fill-ignored", "parameter": parameter, "area_fill_id": int(updated.get("area_fill_id", 0))})
        updated["events"] = events
        return updated
    updated["fill_selector"] = selector
    if int(updated["width"]) == 0 or int(updated["height"]) == 0:
        events.append({"kind": "rectangle-fill-size-missing", "selector": selector})
        updated["events"] = events
        return updated

    width = unpack12(int(updated["width"]))[0]
    height = unpack12(int(updated["height"]))[0]
    cursor_x = unpack12(int(updated["cursor_x"]))[0]
    cursor_y = unpack12(int(updated["cursor_y"]))[0]
    page_width = int(updated["page_width"])
    page_height = int(updated["page_height"])
    origin_x = cursor_x
    origin_y = cursor_y
    saved_x_long = 0
    saved_y_long = 0

    if origin_x > page_width - 1 or (origin_x < 0 and origin_x + width < 0):
        events.append({"kind": "rectangle-fill-ignored", "reason": "horizontal-outside"})
        updated["events"] = events
        return updated
    if origin_x < 0:
        saved_x_long = int(updated["cursor_x"])
        width += origin_x
        origin_x = 0
    if origin_y > page_height - 1 or (origin_y < 0 and origin_y + height < 0):
        events.append({"kind": "rectangle-fill-ignored", "reason": "vertical-outside"})
        updated["events"] = events
        return updated
    if origin_y < 0:
        saved_y_long = int(updated["cursor_y"])
        height += origin_y
        origin_y = 0

    max_width = page_width - origin_x
    max_height = page_height - origin_y
    if int(updated.get("orientation", 0)) == 0:
        queued_x = origin_x
        queued_y = origin_y
        queued_width = min(width, max_width)
        queued_height = min(height, max_height)
    else:
        right_edge = min(page_width - 1, cursor_x + width - 1)
        queued_x = origin_y
        queued_y = page_width - right_edge - 1
        queued_width = min(height, max_height)
        queued_height = min(width, max_width)

    if queued_width <= 0 or queued_height <= 0:
        events.append({"kind": "rectangle-fill-ignored", "reason": "empty-after-clip"})
        updated["events"] = events
        return updated

    page_record = dict(updated.get("page_record", {}))
    result = queue_rectangle_rule_via_13386(page_record, {
        "x": queued_x,
        "y": queued_y,
        "width": queued_width,
        "height": queued_height,
        "flags": selector,
    })
    updated["page_record"] = page_record
    updated["page_roots"] = int(updated.get("page_roots", 0)) + 1
    events.append({
        "kind": "rectangle-filled",
        "selector": selector,
        "source": {"x": queued_x, "y": queued_y, "width": queued_width, "height": queued_height},
        "saved_x": saved_x_long,
        "saved_y": saved_y_long,
        "object": result["object"],
    })
    updated["events"] = events
    return updated


def render_rectangle_command_stream_via_10898(data: bytes, stream: bytes, initial_state: dict[str, object]) -> dict[str, object]:
    state = dict(initial_state)
    pos = 0
    while pos < len(stream):
        if stream[pos] != 0x1B:
            raise AssertionError(f"rectangle command stream expected ESC at offset {pos}")
        start = pos
        pos += 1
        if pos + 1 >= len(stream) or stream[pos] != ord("*") or stream[pos + 1] != ord("c"):
            raise AssertionError(f"rectangle command stream only models ESC *c commands at offset {start}")
        pos += 2
        while True:
            command_start = start if pos == start + 3 else pos
            if pos < len(stream) and (stream[pos] in (ord("+"), ord("-")) or chr(stream[pos]).isdigit()):
                parameter, pos = parse_pcl_decimal_parameter(stream, pos)
            else:
                parameter = 0
            if pos >= len(stream):
                raise AssertionError("rectangle command stream missing final byte")
            final = stream[pos]
            pos += 1
            final_upper = final & ~0x20 if ord("a") <= final <= ord("z") else final
            sequence = stream[command_start:pos]
            before_count = len(state.get("events", []))

            if final_upper == ord("A"):
                state = apply_rectangle_size_dots(state, "width", parameter)
                handler = 0x010E68
            elif final_upper == ord("B"):
                state = apply_rectangle_size_dots(state, "height", parameter)
                handler = 0x010E22
            elif final_upper == ord("H"):
                state = apply_rectangle_size_decipoints(state, "width", parameter)
                handler = 0x010A40
            elif final_upper == ord("V"):
                state = apply_rectangle_size_decipoints(state, "height", parameter)
                handler = 0x010AE0
            elif final_upper == ord("G"):
                state = apply_rectangle_area_fill_id_via_10dce(state, parameter)
                handler = 0x010DCE
            elif final_upper == ord("P"):
                state = apply_fill_rectangle_via_10898(state, parameter)
                handler = 0x010898
            else:
                raise AssertionError(f"unsupported rectangle command ESC *c#{chr(final)} at offset {command_start}")

            events = list(state.get("events", []))
            for event_index in range(before_count, len(events)):
                event = dict(events[event_index])
                event.update({
                    "sequence": sequence,
                    "parameter": parameter,
                    "handler": handler,
                    "chained": bool(ord("a") <= final <= ord("z")),
                })
                events[event_index] = event
            state["events"] = events

            if not (ord("a") <= final <= ord("z")):
                break

    page_record = state.get("page_record", {})
    assert isinstance(page_record, dict)
    bridged = bridge_page_record_via_1edc6(page_record) if page_record else {"rule_list": []}
    rendered = render_rule_list_via_1f446(data, bridged) if bridged.get("rule_list") else None
    return {
        "stream": stream,
        "state": state,
        "events": list(state.get("events", [])),
        "page_record": page_record,
        "bridged": bridged,
        "rendered": rendered,
    }


def render_bridged_compact_bucket_object(data: bytes, resources: bytes, render_record: dict[str, object]) -> dict[str, object]:
    obj = render_record["bucket_root"]
    context_slots = render_record["context_slots"]
    if not isinstance(obj, bytes):
        raise AssertionError("bridged render-record fixture needs one compact bucket object")
    if not isinstance(context_slots, tuple):
        raise AssertionError("bridged render-record fixture needs context slots")
    return render_compact_text_bucket_object(data, resources, context_slots, obj)


def classify_bucket_chain_via_1efc2(data: bytes, render_record: dict[str, object]) -> dict[str, object]:
    """Model the 0x1efc2 selected-bucket walk and first object-class split."""
    fields = render_record.get("render_record_fields", {})
    if not isinstance(fields, dict):
        fields = {}
    bucket_word = int(fields.get("word_10", render_record.get("word_10", 0))) & 0xFFFF
    bucket_heads = render_record.get("bucket_array_18", fields.get("bucket_array_18"))
    if not isinstance(bucket_heads, dict):
        raise AssertionError("0x1efc2 fixture needs render-record bucket array at +0x18")
    chain = bucket_heads.get(bucket_word, [])
    if not isinstance(chain, list):
        raise AssertionError("0x1efc2 fixture bucket entry must be a list of bucket objects")

    entries: list[dict[str, object]] = []
    for index, bucket_object in enumerate(chain):
        obj = bytes(bucket_object)
        if len(obj) < 6:
            raise AssertionError("0x1efc2 fixture bucket object must include link and selector bytes")
        object_byte_4 = obj[4]
        class_mask = object_byte_4 & 0xC0
        entry: dict[str, object] = {
            "chain_index": index,
            "next_link": u32(obj, 0),
            "object_byte_4": object_byte_4,
            "class_mask": class_mask,
        }
        if class_mask == 0:
            compact_selector_bits = object_byte_4 & 0x30
            compact_table_entry = 0x1F024 + (compact_selector_bits >> 2)
            entry.update({
                "branch": "compact",
                "target": 0x01EFFE,
                "compact_selector_bits": compact_selector_bits,
                "compact_table_entry": compact_table_entry,
                "compact_table_target": u32(data, compact_table_entry),
                "context_slot": obj[5] & 0x0F,
            })
        elif class_mask & 0x80:
            encoded_mode = obj[5] & 0x03
            encoded_table_entry = 0x1F8CA + encoded_mode * 4
            entry.update({
                "branch": "encoded-span",
                "target": 0x01F88E,
                "encoded_mode": encoded_mode,
                "encoded_table_entry": encoded_table_entry,
                "encoded_table_target": u32(data, encoded_table_entry),
            })
        else:
            entry.update({
                "branch": "segment-list",
                "target": 0x01F812,
            })
        entries.append(entry)

    return {
        "bucket_word_10": bucket_word,
        "bucket_slot_offset": bucket_word * 4,
        "entries": entries,
        "empty": not entries,
    }


def render_segment_list_object_via_1f812(data: bytes, obj: bytes, dest_stride: int = 0x20, band_rows: int = 16) -> dict[str, object]:
    """Model the 0x1f812 segment-list bucket renderer."""
    if len(obj) < 8:
        raise AssertionError("segment-list object must include link, selector, and count")
    if obj[4] & 0xC0 != 0x40:
        raise AssertionError("segment-list fixture requires object byte +4 high bits 0x40")
    count = u16(obj, 6)
    offset = 8
    dest = bytearray(band_rows * dest_stride)
    rendered: list[dict[str, object]] = []
    max_width = 0
    max_row = 0

    for index in range(count):
        if offset + 6 > len(obj):
            raise AssertionError("segment-list object ended before all entries")
        coord = u16(obj, offset)
        row_count = obj[offset + 2] & 0x0F
        width_word = u16(obj, offset + 4)
        offset += 6

        decoded = coord_decode(coord, band_base=0, payload_offset=0)
        row = int(decoded["row_index"])
        byte_offset = int(decoded["byte_pair_offset"])
        full_words = width_word >> 4
        mask_index = width_word & 0x0F
        trailing_mask = u16(data, 0x308F2 + mask_index * 2)
        if row + row_count > band_rows:
            raise AssertionError("segment-list fixture crosses the synthetic band")
        for row_offset in range(row_count):
            start = (row + row_offset) * dest_stride + byte_offset
            for word_index in range(full_words):
                dest[start + word_index * 2 : start + word_index * 2 + 2] = b"\xff\xff"
            mask_start = start + full_words * 2
            dest[mask_start : mask_start + 2] = trailing_mask.to_bytes(2, "big")

        width_pixels = byte_offset * 8 + full_words * 16 + mask_index
        max_width = max(max_width, width_pixels)
        max_row = max(max_row, row + row_count)
        rendered.append({
            "entry_index": index,
            "coord": coord,
            "decoded": decoded,
            "row_count": row_count,
            "width_word": width_word,
            "full_words": full_words,
            "mask_index": mask_index,
            "trailing_mask": trailing_mask,
            "target": 0x01F862,
        })

    return {
        "selector": obj[4],
        "count": count,
        "entries": rendered,
        "rows": bitmap_bytes_to_rows(dest, max_row, max_width, dest_stride),
    }


def raster_graphics_state(**overrides: int) -> dict[str, int]:
    state = {
        "baseline_word": 0,
        "row_y": 0,
        "mode": 3,
        "origin_long": 0,
        "scale": 4,
        "limit": 0,
        "active": 0,
        "orientation": 0,
        "cursor_axis0": 0,
        "cursor_axis1": 0,
        "origin_source": 0,
        "page_extent": 255,
    }
    state.update(overrides)
    return state


def recompute_raster_limit_via_3324a(state: dict[str, int]) -> int:
    denominator = int(state["scale"]) << 3
    if denominator <= 0:
        raise AssertionError("raster scale denominator must be positive")
    numerator = int(state["page_extent"]) - int(state["baseline_word"]) + 1
    if numerator <= 0:
        return 0
    return (numerator + denominator - 1) // denominator


def apply_raster_resolution_via_10808(state: dict[str, int], parameter: int) -> dict[str, int]:
    state = dict(state)
    if state["active"]:
        return state
    value = abs(int(parameter))
    if value > 150:
        scale = 1
    elif value > 100:
        scale = 2
    elif value > 75:
        scale = 3
    else:
        scale = 4
    state["scale"] = scale
    state["limit"] = recompute_raster_limit_via_3324a(state)
    state["mode"] = scale - 1
    return state


def start_raster_graphics_via_1075a(state: dict[str, int], parameter: int) -> dict[str, int]:
    state = dict(state)
    if state["active"]:
        return state
    state["active"] = 1
    value = abs(int(parameter))
    if value == 1:
        if state["orientation"]:
            state["origin_source"] = 0x782C8E
            state["origin_long"] = int(state["cursor_axis1"])
        else:
            state["origin_source"] = 0x782C8A
            state["origin_long"] = int(state["cursor_axis0"])
    else:
        state["origin_source"] = 0
        state["origin_long"] = 0
    state["baseline_word"] = (int(state["origin_long"]) >> 16) & 0xFFFF
    state["limit"] = recompute_raster_limit_via_3324a(state)
    return state


def end_raster_graphics_via_107fa(state: dict[str, int]) -> dict[str, int]:
    state = dict(state)
    state["active"] = 0
    return state


def raster_transfer_gate_via_105d0(
    page_record: dict[str, object],
    raster_state: dict[str, int],
    parameter: int,
    payload: bytes,
) -> dict[str, object]:
    state = dict(raster_state)
    byte_count = abs(int(parameter))
    state["active"] = 1
    row_y = int(state["row_y"])
    page_extent = int(state.get("page_extent", 0xFFFF))
    limit = max(int(state.get("limit", byte_count)), 0)

    if len(payload) < byte_count:
        raise AssertionError("0x105d0 transfer fixture payload shorter than parsed byte count")

    if row_y > page_extent:
        return {
            "path": "skip-row-beyond-extent",
            "queued": False,
            "drained": byte_count,
            "active": state["active"],
            "byte_count": byte_count,
            "stored_byte_count": 0,
            "overflow_count": 0,
            "row_y": row_y,
            "page_extent": page_extent,
            "page_root": None,
            "state_after": state,
        }

    if row_y < 0:
        return {
            "path": "skip-negative-row",
            "queued": False,
            "drained": byte_count,
            "active": state["active"],
            "byte_count": byte_count,
            "stored_byte_count": 0,
            "overflow_count": 0,
            "row_y": row_y,
            "page_extent": page_extent,
            "page_root": None,
            "state_after": state,
        }

    stored_byte_count = min(byte_count, limit)
    overflow_count = byte_count - stored_byte_count
    page_root = ensure_page_record_root_for_queue(state)
    transfer_state = {
        "x": int(state["baseline_word"]),
        "y": row_y,
        "byte_count": stored_byte_count,
        "mode": int(state["mode"]),
    }
    result = queue_raster_row_to_page_record_via_13070(page_record, transfer_state, payload[:stored_byte_count])
    return {
        "path": "queued-capped" if overflow_count else "queued",
        "queued": True,
        "drained": 0,
        "active": state["active"],
        "byte_count": byte_count,
        "stored_byte_count": stored_byte_count,
        "overflow_count": overflow_count,
        "row_y": row_y,
        "page_extent": page_extent,
        "limit": limit,
        "transfer_state": transfer_state,
        "result": result,
        "page_root": page_root,
        "state_after": state,
    }


