    def parser_handler_summary(trace: dict[str, object]) -> list[int]:
        events = trace["events"]
        assert isinstance(events, list)
        handlers: list[int] = []
        for trace_event in events:
            assert isinstance(trace_event, dict)
            handlers.append(int(trace_event["handler"]))
        return handlers

